var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그래서, 날아간 학우들을 찾는 일에 협조해 달라...... 그런 말씀이십니까?","JPN":"で、飛ばされた学友たちを探すのを手伝ってほしい……ということですか？","ENG":"So, you want me to help you find some students who were blown away. Is that correct?","TWN":"所以，妳們希望我幫忙一起尋找炸飛的失蹤同學……是這意思嗎？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"응, 그렇게 됐어.","JPN":"うん、そういうことよ。","ENG":"Yes.","TWN":"嗯，就是這樣。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"위상 방벽이 망가진 곳을 통해서 침식체들이 계속 들어오고 있는 모양이더라고.","JPN":"位相防壁が壊れた所から、侵食体が次々と入ってきてるみたいなの。","ENG":"Corrupted Objects are constantly sneaking into the city through the holes in the phase barrier.","TWN":"據說，侵蝕體正通過相位屏障被破壞的地方不斷湧進來。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아까 등굣길에 봤는데, 피난이 끝난 시가지 쪽은 침식체에게 이미 점령당했나 봐.","JPN":"さっき登校しながら見たんだけど、避難が終わった市街地のほうは侵食体に占領されたみたい。","ENG":"I saw on my way to school today that the streets that had been vacated are already infested with them.","TWN":"就像剛才在上學的路上看到的一樣，疏散完畢的街道很有可能已經被侵蝕體佔領了。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"이곳 저곳 찾아 다니려면 한 명이라도 더 많은 편이 좋잖아?","JPN":"あちこち探さないといけないから、一人でも多いほうがいいでしょう？","ENG":"Since we have to search everywhere, we need all the help we can get.","TWN":"我們就到處找找看，如果能多一個人來找不是很好嗎？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"미안하지만 부탁 좀 할게, 사서님?","JPN":"申し訳ないけどお願いね、司書さん？","ENG":"Please, Librarian. Help us, please?","TWN":"有件事我感到很抱歉，但我必須要拜託您。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"공적인 업무를 수행할 때는 학생회 서기라는 명칭을 사용해 주시기 바랍니다.","JPN":"公的業務を行う時は、生徒会書記という名称を使っていただけますか？","ENG":"Please address me as the Student Council Clerk when we're discussing official matters.","TWN":"我希望您在執行公務時，能以學生會書記作為稱呼。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그보다 얘기를 듣고도 믿기 어렵군요. 선도부장, 당신이 이런 사고를 일으킬 줄이야.","JPN":"それより信じられない話ですね。\\n風紀委員長、まさかあなたがこんな事故を起こすとは。","ENG":"By the way, this is hard to believe. Student Guide Leader, you never cause trouble.","TWN":"不然聽到這些事情的人大概都會感到不可置信，沒想到我們的先鋒部隊長竟然會引起這樣的意外。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"면목없다...... 감정에 휩쓸려 출력을 너무 올렸어......","JPN":"すまない……感情に流されて出力を上げ過ぎてしまった……","ENG":"I'm ashamed... I let my emotions get the worst of me...","TWN":"真是慚愧…就因為我一時衝動，不小心提高了輸出功率……"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"흠, 그 냉철하던 선도부장도 유진 양처럼 실수를 할 때가 있다니 의외군요.","JPN":"ふむ、あの冷徹な風紀委員長もシロコさんのようなミスをすることがあるなんて意外です。","ENG":"Hmm, even you can be as troublesome as Eujin sometimes.","TWN":"嗯，沒想到一向冷靜的先鋒部隊長也有像劉珍一樣闖禍的時候啊，真令人意外。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"야! 왜 하필 거기서 내 이름이 나오는 건데?","JPN":"おい！　なんでそこで俺の名前が出てくるんだ？","ENG":"Hey, why did you say my name?","TWN":"喂！為什麼我的名字會在這時候出現啊？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그야 원래부터 사사건건 문제를 일으키는 건 유진 양 전담이었지 않습니까?","JPN":"だって、いつも何か問題を引き起こすのはシロコさんだったじゃないですか。","ENG":"Because you're always a troublemaker.","TWN":"因為妳就是專業製造問題機小劉珍啊~"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"뭐야, 짜샤?!","JPN":"何だと？　こら！","ENG":"What? You schmuck!","TWN":"妳說什麼，小鬼！！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그런 끓는 점이 낮은 성격도 문제입니다.","JPN":"そのすぐにカッとなる性格も問題ですよ。","ENG":"You're quick to anger, too.","TWN":"然後燃點低的性格也是個問題。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"도서관에는 명상에 대한 서적도 비치되어 있습니다.","JPN":"図書館には瞑想に関する書籍も備えられています。","ENG":"We have good meditation books at the Library.","TWN":"圖書館裡有些關於冥想的書籍..."},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"심리학적인 부분에는 조예도 관심도 없지만, 유진 양이 그 다혈질을 치료하고 싶다면 몇 권 추천해 드리죠.","JPN":"心理学的な分野は造詣も興味もありませんが、\\nシロコさんがその血の気の多い性格を直したいなら何冊かおすすめしましょう。","ENG":"I'm not interested or knowledgeable in psychology, but I can recommend a few good books if you're interested in anger management.","TWN":"雖然我對心理學方面的書沒什麼興趣，不過要是小劉珍想治療她衝動的毛病，我倒是可以推薦幾本。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"이, 이 자식이 진짜......","JPN":"こ、こいつ……タダじゃおかねぇ……","ENG":"Y-you, you arrogant...","TWN":"這、這傢夥真是..."},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"하하. 그만해, 유진아. 말싸움할 때마다 본전도 못 찾았잖아.","JPN":"あはは。もうやめて、シロコ。口げんかするために来たんじゃないでしょう。","ENG":"Hah hah. Don't, Eujin. You never win when you argue with him.","TWN":"哈哈，算了吧，劉珍。妳不是每次吵架都不會贏嗎？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};